firmware_template.source:
#include "osc_protocol.h"
#include <WiFi.h>
#include <WiFiUdp.h>
#include <OSCMessage.h>
#include <OSCBundle.h>
static WiFiUDP udp;
static osc_cb _cb=nullptr;
void osc_setup(uint16_t p){udp.begin(p);Serial.printf("[osc] OK port=%d\n",p);}
void osc_loop(){OSCMessage msg;int sz=udp.parsePacket();if(sz>0){while(sz--)msg.fill(udp.read());}}
void osc_send(const char*h,uint16_t p,const char*a,float v){OSCMessage msg(a);msg.add(v);udp.beginPacket(h,p);msg.send(udp);udp.endPacket();}
void osc_on_message(osc_cb cb){_cb=cb;}
